import type { Tree } from '@lezer/common';

import type { FilterFieldSuggestionType } from '../../types/suggestions.js';
import type {
  FilterFieldLeafNode,
  FilterFieldLezerNodeType,
  FilterFieldStatementNode,
  FilterFieldStatementTokenType,
  FilterFieldValueNode,
} from '../../types/tree-nodes.js';
import { getTextFromRange } from '../get-text.js';
import { isFilterFieldListNode } from '../tree-node-guards.js';

/** @internal */
export type FilterFieldOverlappingSuggestions = {
  type: FilterFieldSuggestionType[number];
  subToken: FilterFieldLeafNode;
};

/** @internal */
export function getSuggestionCategory(args: {
  currentStatement?: FilterFieldStatementNode;
  currentToken: FilterFieldValueNode;
  currentTokenType?: FilterFieldStatementTokenType;
  prevNode: FilterFieldLezerNodeType | 'FilterValue';
  tree: Tree;
  doc: string;
  cursorPosition: number;
}): {
  suggestionType: FilterFieldSuggestionType[number];
  showLogicalOperators: boolean;
  showInclusionOperators: boolean;
  overlappingSuggestions?: FilterFieldOverlappingSuggestions;
} {
  const {
    currentStatement,
    currentToken,
    currentTokenType,
    prevNode,
    tree,
    doc,
    cursorPosition,
  } = args;

  let treeCursor = tree.cursorAt(cursorPosition, -1);

  if (treeCursor.node.name === 'Filter') {
    treeCursor = tree.cursorAt(cursorPosition, 1);
  }

  const isFreeText = treeCursor.node.name === 'FreeText';

  // Move to first child ending before cursor position.
  treeCursor.childBefore(cursorPosition);

  let showInclusionOperators = false;
  let showLogicalOperators = false;
  let suggestionType: FilterFieldSuggestionType[number] = 'key';

  // Depending on the current cursor position and the already defined parts
  // of the filter statement at the cursor position, the provided suggestions
  // and flags for which suggestions to show in the suggestions overlay are
  // set accordingly.
  if (
    // Not at the first token, first token inside group and either:
    // - no statement at the current position e.g. "a = b |"
    // - started typing a key e.g. "a = b o|"
    // - just typed a logical operator, but no space yet e.g. "a = b or|"
    // -> show logical operator suggestions. (if the key that is typed does not start with o, the
    // or suggestion will be removed when filtering the suggestions)
    currentToken?.range.from !== 0 &&
    // Case 1: no statement at the current position e.g. "a = b |"
    ((currentStatement === undefined &&
      prevNode !== 'LogicalOperator' &&
      prevNode !== 'FilterKey' &&
      prevNode !== 'ComparisonOperator' &&
      prevNode !== 'OpeningBracket') ||
      // Case 2: started typing a key e.g. "a = b o|"
      (!!currentStatement &&
        currentTokenType === 'key' &&
        prevNode !== 'LogicalOperator' &&
        treeCursor?.node?.parent?.node?.prevSibling?.name !==
          'OpeningBracket') ||
      // Case 3: just typed a logical operator, but no space yet e.g. "a = b or|"
      (prevNode === 'LogicalOperator' &&
        !!currentToken?.textValue &&
        treeCursor?.node?.prevSibling?.name !== 'OpeningBracket'))
  ) {
    showLogicalOperators = true;
  } else if (
    (currentTokenType === 'value' && !Array.isArray(currentToken.value)) ||
    (currentToken.type === 'String' &&
      !currentToken.value &&
      currentStatement &&
      !currentStatement.value &&
      prevNode !== 'FilterKey')
  ) {
    // This case handles value suggestions if there is either an invalid value in the
    // value spot (e.g. a = $) or there is no value yet
    suggestionType = 'value';
  } else if (
    currentToken.type === 'Key' &&
    ((currentStatement?.comparisonOperator !== undefined &&
      currentStatement.comparisonOperator.type !== 'Error') ||
      currentStatement?.value !== undefined)
  ) {
    suggestionType = 'key';
  } else if (
    (prevNode === 'FilterKey' &&
      (currentToken.type === 'String' || currentToken.type === 'Error')) ||
    currentToken.type === 'ComparisonOperator' ||
    currentToken.type === 'InclusionOperator' ||
    currentToken.type === 'ExistsOperator' ||
    (prevNode === 'InvalidComparisonOperator' &&
      cursorPosition <=
        (currentStatement?.comparisonOperator?.range.to ?? 0)) ||
    (currentToken.type === 'Error' && currentTokenType === 'comparisonOperator')
  ) {
    // Previous node is a filter key and the delimiter is already entered or
    // previous node is a comparison operator -> show comparison operators.
    suggestionType = 'comparisonOperator';
  } else if (
    // List suggestions need to be handled separately since we don't want to replace the whole list
    // token, but only the list values when applying suggestions. Only the list value at the cursor
    // position should be returned as `currentToken` that can be used for filtering suggestions.
    Array.isArray(currentToken.value) &&
    isFilterFieldListNode(currentToken)
  ) {
    suggestionType = 'value';
  }

  if (
    (prevNode === 'ComparisonOperator' &&
      cursorPosition > treeCursor.node.to &&
      (currentStatement?.comparisonOperator?.range.to ?? 0) <
        (currentStatement?.value?.range.from ?? 0) &&
      currentTokenType !== 'comparisonOperator') ||
    (prevNode === 'ComparisonOperator' && !currentStatement) ||
    prevNode === 'FilterValue' ||
    (prevNode === '⚠' && currentTokenType === 'value')
  ) {
    suggestionType = 'value';
  }

  if (
    prevNode === 'InclusionOperator' &&
    cursorPosition > treeCursor.node.to &&
    treeCursor.nextSibling() &&
    treeCursor.node.name === 'FilterIncludesValue'
  ) {
    const { from } = treeCursor.node;
    const characterBeforeCursor = getTextFromRange(
      {
        from: from - 1,
        to: from,
      },
      doc,
    );

    if (characterBeforeCursor === ' ') {
      showInclusionOperators = true;
    }

    suggestionType = 'none';
  }

  if (
    prevNode === 'OpeningBracket' &&
    treeCursor.nextSibling() &&
    treeCursor.node.name === '⚠'
  ) {
    showInclusionOperators = true;
  }

  if (
    prevNode === 'ExistsOperator' &&
    currentTokenType === 'comparisonOperator'
  ) {
    if (cursorPosition < currentToken.range.to) {
      suggestionType = 'comparisonOperator';
    } else {
      suggestionType = 'value';
    }
  }

  let overlappingSuggestions: FilterFieldOverlappingSuggestions | undefined =
    undefined;
  if (isFreeText && suggestionType === 'key') {
    overlappingSuggestions = getOverlappingSuggestionTypes(
      currentToken,
      cursorPosition,
    );
  }

  return {
    suggestionType,
    showLogicalOperators,
    showInclusionOperators,
    overlappingSuggestions,
  };
}

// Matches an unescaped space that potentially splits up a token into multiple tokens.
// https://regex101.com/r/2ECDw8/1
export const SPLIT_TOKEN_REGEX = /(?<!\\)(?:\\\\)*  */g;

// Matches a trailing space, exclamation mark or any of the trailing keywords specified for retreiving overlapping suggestions.
// https://regex101.com/r/N3aLqe/1
export const SHOW_OPERATOR_REGEX =
  /(?<!\\)(?:\\\\)*((?<rightAssociative>[ !])| (?<keyword>i|n|in|no|not|not i|not in) ?)$/d;

/**
 * Returns possibly overlapping suggestion categories for the current cursor position and token.
 * e.g. ›health |!‹ can have key and comparison operator suggestions.
 */
function getOverlappingSuggestionTypes(
  currentToken: FilterFieldValueNode,
  cursorPosition: number,
): FilterFieldOverlappingSuggestions | undefined {
  const { range, textValue } = currentToken;
  const neutralizedCursorPosition = cursorPosition - range.from;

  let subTokenSeparator: RegExpExecArray | null = null;
  let nextMatch: RegExpExecArray | null = null;

  const matchSubToken = new RegExp(SPLIT_TOKEN_REGEX, 'g');
  while ((nextMatch = matchSubToken.exec(textValue)) !== null) {
    subTokenSeparator = nextMatch;
  }

  const operatorSeparators = new RegExp(SHOW_OPERATOR_REGEX).exec(textValue);

  if (!subTokenSeparator && !operatorSeparators) {
    return;
  }

  if (operatorSeparators) {
    const offsetSpace = textValue.slice(-1) === ' ' ? 1 : 0;
    /*
      For properly filtering overlapping comparison operator suggestions, we need to use only part of the current token.
      The current token may be split as follows:
      - separated by a space
        ›foo i‹
        space matches the split token regex
        i matches as keyword
        subtoken: "i"
      - trailing space
        ›foo ‹
        space matches the right associative group of SHOW_OPERATOR_REGEX
        subtoken: " "
      - trailing exclamation mark
        ›foo!‹
        exclamation mark matches the right associative group of SHOW_OPERATOR_REGEX
        subtoken: "!"
     */
    const {
      keyword,
      rightAssociative,
    }: { keyword?: string; rightAssociative?: string } =
      operatorSeparators.groups ?? {};
    const trimmedTokenValue = (rightAssociative ?? '').trim();

    const {
      keyword: keywordIndices,
      rightAssociative: rightAssociativeIndices,
    } = operatorSeparators.indices?.groups ?? {};

    if (neutralizedCursorPosition >= keywordIndices?.[0]) {
      return {
        type: 'comparisonOperator',
        subToken: {
          type: 'String',
          value: keyword ?? trimmedTokenValue,
          textValue: keyword ?? trimmedTokenValue,
          range: {
            from: range.from + keywordIndices[0],
            to: range.from + keywordIndices[1] + offsetSpace,
          },
        },
      };
    }

    if (neutralizedCursorPosition > rightAssociativeIndices?.[0]) {
      return {
        type: 'comparisonOperator',
        subToken: {
          type: 'String',
          value: keyword ?? trimmedTokenValue,
          textValue: keyword ?? trimmedTokenValue,
          range: {
            from: range.from + rightAssociativeIndices[0] + offsetSpace,
            to: range.from + rightAssociativeIndices[1],
          },
        },
      };
    }
  }
}
